/**
 * Official Type definitions for LemonadeJS Schedule Event Modal
 * https://lemonadejs.net
 */

declare function Event(el: HTMLElement, options?: Event.Options): Event.Instance;

declare namespace Event {

    interface EventData {
        /** Event title */
        title?: string;
        /** Date in ISO format (YYYY-MM-DD) */
        date?: string;
        /** Start time in HH:MM format */
        start?: string;
        /** End time in HH:MM format */
        end?: string;
        /** Location */
        location?: string;
        /** Hex color */
        color?: string;
        /** Guid identification */
        guid?: string;
    }

    interface Options {
        /** Valid time range to show in time selection dropdowns. Format: ['08:00', '18:00'] */
        validRange?: string[];
    }

    interface Instance {
        /** Valid time range configuration */
        validRange?: string[];
        /** Color palette for event colors */
        palette: string[][];
        /** Reference to the modal instance */
        modal: any;
        /** Reference to the form element */
        form: HTMLFormElement;
        /** Open the event modal for editing
         * @param record - Event data to edit
         * @param callback - Callback function to call when saving (receives updated event data)
         */
        open: (record: EventData, callback: (data: EventData) => void) => void;
    }
}

export default Event;
